import csv
from typing import List, Dict, Iterator


class DataLoader:
    def read_csv(self, filepath: str) -> List[Dict]:
        with open(filepath) as f:
            reader = csv.DictReader(f)
            return list(reader)

    def read_csv_chunks(self, filepath: str, chunk_size: int = 1000) -> Iterator[List[Dict]]:
        """Yield chunks of rows from a CSV file."""
        with open(filepath) as f:
            reader = csv.DictReader(f)
            chunk = []
            for row in reader:
                chunk.append(dict(row))
                if len(chunk) >= chunk_size:
                    yield chunk
                    chunk = []
            if chunk:  # Don't forget the last partial chunk
                yield chunk
